VALUES
  ('aboriginal-0a2fc18c-moex-00153', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '如果某養殖場的石斑魚存活量上升，則該養殖場的：', '["勞動需求增加", "勞動需求減少", "勞動供給增加", "勞動供給減少"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00154', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設廠商的利潤水準與市場價格呈現遞增的凸函數，如下圖所示。廠商現在面對的市場價格是20 元，可獲得利潤20萬。但廠商對於未來市場價格的走勢不確定，且認為有一半的機率價格會上揚 到25元，有一半的機率價格會下跌到15元。若廠商的目標是追求預期利潤水準極大化，依據圖 形下列敘述何者正確？', '["廠商是風險趨避者", "廠商覺得未來賺錢的前景會比目前好", "廠商覺得未來賺錢的前景會比目前差", "廠商覺得未來賺錢的前景不會比目前差，也不會比目前好"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00155', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '有關資源配置滿足柏拉圖效率（Paretoefficiency）之敘述，下列何者正確？', '["相對於本身的消費組合，沒有一位消費者更偏好其他人的消費組合", "資源的分配方式可以降低社會不均度", "無法在不損及其他人效用的情形下提高某一人的效用", "整體社會可以將資源分配給最多的消費者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00156', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '有關污染管制之公共政策，下列敘述何者正確？', '["若就相同的污染減量而言，管制比課稅來得有效率", "污染排放權其最終的分配是否有效率，取決於排放權的最初分配方式", "污染稅可使內部性外部化，並增加政府稅收", "若某一產品之生產過程會產生污染，則其供給曲線位於社會成本曲線的下方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00157', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '在其他條件不變下，若一個封閉體系的政府支出增加，但可貸資金市場的均衡實質利率卻維持不 變。下列敘述何者最有可能發生？', '["廠商增加投資", "政府提高儲蓄利息的免稅額度", "所有消費者增加消費", "所有消費者減少儲蓄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00158', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '在某一個經濟體的總生產函數為 Y=K0.5N0.5，勞動投入之淨成長率為 3%，家計單位的所得中有 t t t 70%消費掉。則在長期之下，每塊錢投資之利潤率為何？', '["5%", "6%", "7%", "8%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00159', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '關於失業的敘述，下列何者正確？', '["充分就業下的自然失業率通常為零", "摩擦性失業的主要原因是經濟不景氣所造成的", "失業是指15歲以上的民間人口，積極在找工作且可以馬上工作，但找不到工作的人", "怯志勞工（discouragedworker）是指在經濟不景氣時，勞工的工作量減少或是被迫放無薪假之 情況"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00160', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '梭羅剩餘（Solow''sresidual）衡量產出成長中無法被下列何者解釋的部分？', '["技術進步", "資本與勞工的成長", "貨幣供給成長", "儲蓄率增加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00161', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '根據自然率假說（naturalratehypothesis）的內容，貨幣成長率提高的影響為何？', '["在長期僅會影響通貨膨脹，不會影響自然失業率", "在長期會同時讓自然產出上升、自然失業率下滑", "在短期會讓自然失業率下降，並提高通貨膨脹率", "在短期讓實際產出高於自然產出，但無法改變實際失業率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00162', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '有關凱因斯學派的總合供給曲線，下列敘述何者正確？', '["在其他條件不變下，勞工預期通貨膨脹上升，將使短期總合供給曲線往右移", "總合供給曲線是不同利率水準下，經濟體系能提供的最終商品和服務之總量", "長期總合供給曲線是一條通過自然失業率（naturalrateofunemployment）的正斜率曲線", "在其他條件不變下，勞動參與率（laborforceparticipationrate）的提高將使得長期總合供給曲線 往右移"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL)
